VALUES
  ('cpa-moex-00301', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法第110條規定，乙公司110年營利事業所得稅結算申報為營業虧損200萬元，稽徵機 關查獲短漏報所得 60 萬元，加計短漏所得額後核定其營利事業所得額仍為虧損，不考量減免處 罰情形下，其應處罰鍰金額？', '["24萬元", "12萬元", "9萬元", "6萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00302', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法及相關法規規定，下列何者不符合房地合一課徵所得稅新制有關自住房地租稅優惠之 條件？', '["個人與其配偶及未成年子女於該房屋辦竣戶籍登記連續滿8年", "個人或其配偶於該房屋連續居住滿7年", "個人與其配偶及成年子女於交易前6年內未曾適用自住房地優惠", "房屋在交易前7年內，未曾出租、供營業或執行業務使用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00303', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '非屬小規模營利事業之獨資合夥組織，依所得稅法相關規定之申報營利事業所得稅方式，下列敘 述何者錯誤？', '["應辦理結算申報", "免辦理暫繳申報", "應辦理未分配盈餘申報", "應辦理清算申報"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00304', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法及相關法規規定，有關營利事業所得稅申報之罰則，下列敘述何者錯誤？', '["納稅義務人已依本法規定辦理結算、決算或清算申報，而對依本法規定應申報課稅之所得額有 漏報或短報情事者，處以所漏稅額二倍以下之罰鍰", "納稅義務人未依本法規定自行辦理結算、決算或清算申報，而經稽徵機關調查，發現有依本法 規定課稅之所得額者，除依法核定補徵應納稅額外，應照補徵稅額，處三倍以下之罰鍰", "納稅義務人為獨資、合夥組織之營利事業者，應就稽徵機關核定短漏之課稅所得額，按所漏稅 額之半數計算罰鍰", "營利事業已依所得稅法第102條之2規定辦理申報，但有漏報或短報未分配盈餘者，處以所漏 稅額一倍以下之罰鍰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00305', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，保險業下列何種收入適用稅率百分之一？', '["出租房屋收入", "出售固定資產收入", "保險費收入", "再保費收入"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00306', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法及相關法規規定，對有二人鋼琴演奏及演唱的鋼琴酒吧（PUB）課 徵營業稅時，適用下列那一種稅率？', '["5%", "10%", "15%", "25%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00307', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法及相關規定，營業人如有固定營業場所，應於何時向主管稽徵機關 申請稅籍登記？', '["試銷期滿後", "開始營業前", "開始營業後10日內", "無時間限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00308', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法及相關規定，經銷家電產品的公司依經銷契約自家電製造商取得的 獎勵金，經銷商應如何書立憑證？', '["應開立統一發票", "應開立銷貨退回或折讓證明單", "應開立進貨退出或折讓證明單", "應開立銀錢收據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00309', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法及相關規定，外國之事業、機關、團體、組織在我國境內無固定營 業場所，銷售電子勞務予境內自然人，年銷售額超過新臺幣多少元，即應依法向主管稽徵機關申 請稅籍登記？', '["48萬元", "36萬元", "24萬元", "12萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00310', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法及相關法規規定，銷售下列農產品，何者不得免徵營業稅？', '["水果", "香腸", "糙米", "原木"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00311', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法規定，每年11月開徵之地價稅，係以當年何日土地登記簿上所記載之土地所有權人為 納稅義務人？', '["1月1日", "8月31日", "9月22日", "12月31日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00312', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法規定，有關一般土地適用的地價稅稅率之敘述，下列何者錯誤？', '["未超過累進起點地價5倍者，課徵10‰", "超過累進起點地價5倍至10倍者，就其超過部分課徵25‰", "超過累進起點地價15倍至20倍者，就其超過部分課徵45‰", "超過累進起點地價20倍以上者，就其超過部分課徵55‰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00313', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法規定，移轉下列何項土地時，可以申請不課徵土地增值稅？', '["因繼承而移轉之土地", "因被徵收而移轉之土地", "移轉與自然人之作農業使用的農業用地", "移轉與營利事業之作工廠使用的工業用地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00314', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法規定，A公司持有一筆都市計畫公共設施保留地，供其員工做停車使用，該土地課稅 總地價為1,000萬元，當年應繳納地價稅額為若干？', '["10萬元", "6萬元", "2萬元", "0元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00315', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲營利事業自110年9月1日起至110年10月31日依法規定應給與他人憑證而未給與，以及應 自他人取得憑證而未取得，經國稅局於111年1月20日查獲，國稅局於依稅捐稽徵法第44條規 定論處違章時，下列敘述何者為正確？', '["國稅局應就查獲當次查明認定之總額，就甲營利事業未依法規定給與他人憑證及取得憑證之金 額，分別依該條第1項規定之罰鍰額度計算罰鍰金額後，分別適用該條第2項關於處罰金額最 高不得超過新臺幣（下同）100萬元之規定", "國稅局不須區分甲營利事業未依法規定給與他人憑證及取得憑證之金額，直接就查獲當次查明 認定之總額，依該條第1項規定之罰鍰額度計算罰鍰金額，並適用該條第2項關於處罰金額最 高不得超過100萬元之規定", "國稅局於計算罰鍰金額時，須就經查明認定之總額，裁處百分之五罰鍰，但最高不得超過 100 萬元", "國稅局於計算罰鍰金額時，可就經查明認定之總額，裁處百分之五以下罰鍰，但最高可超過100 萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00316', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，下列何種情形，稅捐稽徵人員對於納稅義務人之財產、所得、營業、納稅等 資料應絕對保守秘密？', '["債權人持拍賣抵押物裁定，向稅捐稽徵機關申請查調該抵押人之所得資料", "債權人持金錢給付之確定判決，向稅捐稽徵機關申請查調判決所載債務人之財產資料", "法務部行政執行署所屬行政執行分署因辦理公法上金錢給付義務執行事件之需要，經財政部核 定後函請稅捐稽徵機關提供納稅義務人之財產、所得、營業及納稅資料", "納稅義務人死亡，其繼承人向稅捐稽徵機關申請查調該納稅義務人之財產及所得資料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00317', 'cpa', 'cpa-moex-112-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '下列何者非屬稅捐稽徵法第24條規定之租稅保全措施？', '["辦理禁止處分登記", "向法院聲請裁定拘提管收", "向法院聲請裁定假扣押", "限制出境"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:02+00:00", "source_pdf_sha1": "643b6ecce389", "answer_pdf_sha1": "9e1833e959b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "112", "exam_name": "112年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
